const { AzureFunction, HttpRequest } = require('@azure/functions-proto');
const { Client } = require('twilio')(process.env.TWILIO_ACCOUNT_SID, process.env.TWILIO_AUTH_TOKEN);
const sgMail = require('@sendgrid/mail');

sgMail.setApiKey(process.env.SENDGRID_API_KEY);

module.exports = async function (context: AzureFunction.Context, req: HttpRequest) {
    context.log('JavaScript HTTP trigger function processed a request.');

    const name = req.query.name || (req.body && req.body.name);
    const message = req.query.message || (req.body && req.body.message);
    const phone = req.query.phone;

    if (!name || !message || !phone) {
        context.res = {
            status: 400,
            body: 'Please pass name, message and phone in the request'
        };
        return;
    }

    try {
        await sgMail.send({
            to: process.env.RECIPIENT_EMAIL_ADDRESS,
            from: process.env.SENDER_EMAIL_ADDRESS,
            subject: `Message from ${name}`,
            text: message
        });

        const message = await Client.messages
            .create({
                body: message,
                from: process.env.TWILIO_PHONE_NUMBER,
                to: phone
            })
            .then(message => {
                console.log(message.sid);
            })
            .done();

        context.res = {
            status: 200,
            body: 'Email and SMS sent successfully'
        };
    } catch (error) {
        context.log.error(error);
        context.res = {
            status: 500,
            body: 'Internal Server Error'
        };
    }
};